import React from 'react';
import './Hero.css';

export default function Hero() {
  return (
    <section id="hero" className="hero">
      {/* Hero video background — confirmed working, kept exactly as is per brief */}
      <div className="hero-bg">
        <video autoPlay muted loop playsInline preload="auto">
          <source src="/videos/hero_bg.mp4" type="video/mp4" />
        </video>
      </div>
      <div className="hero-pattern" />

      <div className="hero-content">
        {/* Orvis credential eyebrow per brief item #04 */}
        <div className="hero-eyebrow">
          <span className="eyebrow-line" />
          10 Years Orvis Endorsed · Urubaxi River, Brazil · 240 Miles Private Water
        </div>

        {/* Headline updated to confirmed brand tagline per brief item #21 */}
        <h1 className="hero-title">
          From the Canals<br />
          <em>to the World.</em>
        </h1>

        {/* Original strong line moved to subhead per brief item #21 */}
        <p className="hero-sub">
          World's biggest Peacock Bass. Private river. 240 miles — nobody else gets in.
        </p>

        {/* Reduced from 3 CTAs to 2 per brief item #04 */}
        <div className="hero-btns">
          <a href="#tours" className="btn-gold">Explore Tours</a>
          <a href="#florida-day-trips" className="btn-ghost">Book a Florida Day Trip</a>
        </div>
      </div>

      <div className="hero-scroll">
        <div className="scroll-line" />
        <span>scroll</span>
      </div>
    </section>
  );
}
